            axes[0].plot(t_iv, r_iv, "o-", color=OXFORD, lw=2, ms=5, label="In Vitro Fd")
            axes[0].plot(t_iv, Fa, "s--", color="#c0392b", lw=2, ms=5, label="Fa (Wagner-Nelson)")
            axes[0].set_xlabel(f"Time ({time_unit})")
