            axes[0].set_xlim(left=0); axes[0].set_ylim(0,112)
            axes[0].legend(fontsize=8); axes[0].set_title("Fd vs Fa")
            axes[1].scatter(r_iv, Fa, color=OXFORD, s=60, edgecolors=AMBER, lw=1)
            m,b = np.polyfit(r_iv, Fa, 1)
